sql:
SELECT title
FROM papers
WHERE author_id = 0;

external_knowledge:
- "sowers" metaphorically refers to authors;
- "planted seeds in the fertile soil of academia" symbolizes submitting papers for review;
- "seedlings" metaphorically represents submitted papers;
- "over the last year" indicates a timeframe of one year from the current date;
- "details of their seedlings" refers to information about the papers, including their titles, abstracts, submission dates, and publication formats.

- "Beacon authors" metaphorically represent individuals whose work is significant and guiding. ;
- "Illuminated academic paths" symbolizes the act of contributing substantially to a field of study through multiple published papers. ;
- "Three academic paths" refers to the minimum number of papers (three) required for an author to be considered prolific within a discipline.

- "Prolific authors" refers to those who have more than 3 papers in a particular field (discipline_id = 1);
- "Notable plagiarism concerns" means papers with a plagiarism score greater than 0.2;
- "Recent times" is defined as the last year.

- "sailing under the flag of submission" refers to papers that are in the status of 'submitted';
- "shelter under the wings of internal reviewers" metaphorically indicates the papers are being reviewed by internal reviewers;
- "vessels embarking on their voyages" refers to the papers being associated with specific conferences.

sql:
SELECT a.name
FROM authors AS a
WHERE a.author_id IN (
  SELECT p.author_id
  FROM papers AS p
  WHERE p.plagiarism_score > (
    SELECT AVG(plagiarism_score) FROM papers
  )
);

SELECT paper_id, title, abstract, plagiarism_score
FROM papers
WHERE status = 'Under Review';

SELECT a.name
FROM authors a
WHERE a.discipline_id = (
  SELECT r.discipline_id
  FROM reviewers r
  WHERE r.reviewer_score = (
    SELECT MAX(reviewer_score) FROM reviewers
  )
);

SELECT title
FROM papers
WHERE status = 'published' AND plagiarism_score > 0;
